def task_arithmetic_merge(base_sd, add_vectors, neg_vectors,
                          add_scales=None, neg_scales=None):
    """
    Apply task arithmetic: add positive task vectors, subtract negative ones.
    add_vectors: list of task vectors to add
    neg_vectors: list of task vectors to negate
    """
    if add_scales is None: add_scales = [1.0] * len(add_vectors)
    if neg_scales is None: neg_scales = [1.0] * len(neg_vectors)

    result = {k: base_sd[k].float().clone() for k in base_sd}
    for tau, lam in zip(add_vectors, add_scales):
        for k in result:
            result[k] += lam * tau[k]
    for tau, mu in zip(neg_vectors, neg_scales):
        for k in result:
            result[k] -= mu * tau[k]
    return result

