SKIP_KEYS = {'model.embed_tokens.weight', 'lm_head.weight'}

def safe_add_task_vectors(base_sd, task_vectors, scales=None):
    """Apply task vectors but skip embedding layers."""
    if scales is None: scales = [1.0] * len(task_vectors)
    result = {k: base_sd[k].float().clone() for k in base_sd}
    for tau, lam in zip(task_vectors, scales):
        for k in result:
            if k not in SKIP_KEYS:
                result[k] += lam * tau[k]
    return result
